import{_ as r,o as a,c as o,a2 as e}from"./chunks/framework.Cr-Z7ngm.js";const b=JSON.parse('{"title":"邀请关系","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"rewards/referral-relationship.md","filePath":"zh-CN/rewards/referral-relationship.md"}'),d={name:"rewards/referral-relationship.md"};function n(s,t,l,p,i,h){return a(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="邀请关系" tabindex="-1">邀请关系 <a class="header-anchor" href="#邀请关系" aria-label="Permalink to &quot;邀请关系&quot;">​</a></h1><p>邀请关系是长桥平台记录「谁邀请了谁」的核心机制，直接决定邀请活动奖励能否正确归因和发放。</p><p>平台维护三种独立的邀请关系：</p><table tabindex="0"><thead><tr><th>关系类型</th><th>触发时机</th><th>说明</th></tr></thead><tbody><tr><td><strong>注册邀请关系</strong></td><td>被邀请人完成注册时</td><td>记录谁介绍该用户来到平台</td></tr><tr><td><strong>开户邀请关系</strong></td><td>被邀请人完成 KYC 开户前</td><td>记录谁邀请该用户开户，用于开户奖励归因</td></tr><tr><td><strong>入金邀请关系</strong></td><td>被邀请人首次入金前</td><td>记录谁邀请该用户入金，用于入金邀请奖励归因</td></tr></tbody></table><p>三种关系相互独立，可以对应同一位邀请人，也可以不同（例如注册时没有填邀请码，但开户前补绑了邀请人）。</p><h2 id="如何绑定邀请关系" tabindex="-1">如何绑定邀请关系 <a class="header-anchor" href="#如何绑定邀请关系" aria-label="Permalink to &quot;如何绑定邀请关系&quot;">​</a></h2><h3 id="方式一-注册时通过邀请链接或填写邀请码" tabindex="-1">方式一：注册时通过邀请链接或填写邀请码 <a class="header-anchor" href="#方式一-注册时通过邀请链接或填写邀请码" aria-label="Permalink to &quot;方式一：注册时通过邀请链接或填写邀请码&quot;">​</a></h3><p>这是最常见的方式。系统在注册完成时<strong>立即绑定注册邀请关系</strong>，开户邀请关系和入金邀请关系由系统后续自动同步到同一位邀请人。</p><p><strong>前置条件：</strong></p><ul><li>被邀请人为平台新用户（未曾注册）</li><li>邀请人拥有有效的专属邀请码</li></ul><p><strong>操作步骤：</strong></p><ol><li>邀请人在 APP「活动中心」或个人主页获取专属邀请链接 / 邀请码</li><li>被邀请人通过邀请链接打开 APP，或在注册页手动填写邀请码</li><li>完成注册后，系统绑定注册邀请关系，开户/入金邀请关系随后自动同步</li></ol><p><strong>注意：</strong> 注册完成后，注册邀请关系无法再更改。开户邀请和入金邀请在未完成对应步骤前，仍可通过客服协助补绑或更换邀请人。</p><h3 id="方式二-注册后补绑邀请人-仅限未开户或未入金前" tabindex="-1">方式二：注册后补绑邀请人（仅限未开户或未入金前） <a class="header-anchor" href="#方式二-注册后补绑邀请人-仅限未开户或未入金前" aria-label="Permalink to &quot;方式二：注册后补绑邀请人（仅限未开户或未入金前）&quot;">​</a></h3><p>适用于注册时未填写邀请码、事后想补绑的用户。</p><p><strong>开户邀请关系补绑条件：</strong></p><ul><li>被邀请人尚未完成 KYC 开户（账户状态为未开户）</li><li>邀请人的邀请码有效</li></ul><p><strong>入金邀请关系补绑条件：</strong></p><ul><li>被邀请人尚未完成首次入金</li><li>邀请人的邀请码有效</li></ul><p>一旦完成开户或入金，对应的邀请关系即锁定，<strong>无法再更改或补绑</strong>。</p><h2 id="奖励归因-哪种邀请关系决定谁拿奖励" tabindex="-1">奖励归因：哪种邀请关系决定谁拿奖励 <a class="header-anchor" href="#奖励归因-哪种邀请关系决定谁拿奖励" aria-label="Permalink to &quot;奖励归因：哪种邀请关系决定谁拿奖励&quot;">​</a></h2><p>当三种邀请关系绑定的是<strong>不同的邀请人</strong>时，各任务奖励按以下优先级归因：</p><table tabindex="0"><thead><tr><th>任务类型</th><th>奖励归属优先级</th></tr></thead><tbody><tr><td>注册任务</td><td>注册邀请人</td></tr><tr><td>开户任务（KYC）</td><td>开户邀请人 → 若无则回退至注册邀请人</td></tr><tr><td>入金 / 转仓 / 净资产任务</td><td>入金邀请人 → 若无则开户邀请人 → 若无则注册邀请人</td></tr></tbody></table><p><strong>注意：</strong> 注册邀请关系需在 <strong>2021 年 4 月 28 日之后</strong>建立，才能参与奖励归因。更早的历史注册绑定不触发活动奖励计算。</p><h2 id="绑定限制" tabindex="-1">绑定限制 <a class="header-anchor" href="#绑定限制" aria-label="Permalink to &quot;绑定限制&quot;">​</a></h2><p>以下情况会导致邀请关系绑定<strong>失败</strong>：</p><table tabindex="0"><thead><tr><th>情况</th><th>说明</th></tr></thead><tbody><tr><td>邀请自己</td><td>不能使用自己的邀请码绑定</td></tr><tr><td>互相绑定</td><td>若 A 已邀请 B，则 B 不能反过来邀请 A</td></tr><tr><td>已开户绑开户邀请</td><td>被邀请人已完成 KYC 开户后，无法绑定或变更开户邀请人</td></tr><tr><td>已入金绑入金邀请</td><td>被邀请人已完成首次入金后，无法绑定或变更入金邀请人</td></tr><tr><td>邀请码无效</td><td>邀请码不存在或已失效</td></tr></tbody></table><h2 id="绑定变更与关系纠纷答疑" tabindex="-1">绑定变更与关系纠纷答疑 <a class="header-anchor" href="#绑定变更与关系纠纷答疑" aria-label="Permalink to &quot;绑定变更与关系纠纷答疑&quot;">​</a></h2><p><strong>Q：注册时没填邀请码，现在还能绑定邀请人吗？</strong></p><p>A：注册邀请关系无法补绑。但如果您尚未完成开户（KYC），开户邀请关系仍可补绑；如果您尚未完成首次入金，入金邀请关系也仍可补绑。请联系客服，提供邀请人的邀请码，客服会协助核查并处理。补绑成功后，对应的邀请活动奖励才能正常发放。</p><p><strong>Q：我注册时填了邀请码，为什么开户奖励没有发给我的邀请人？</strong></p><p>A：请确认以下几点：（1）注册时是否成功绑定了邀请关系——可在 APP「我的 → 邀请码」查看您的邀请人信息；（2）邀请活动是否仍在进行中，活动结束后完成的任务通常不计入奖励；（3）奖励发放需要 1-3 个工作日，请耐心等待。如以上均正常但仍未收到奖励，请联系客服核查。</p><p><strong>Q：我的邀请人信息显示的是 A，但我的邀请码是 B 给的，正确吗？</strong></p><p>A：这种情况可能是注册邀请与开户/入金邀请绑定了不同的人，属于正常情况。三种邀请关系各自独立，奖励会分别按对应关系归因。如您认为有误，请联系客服说明情况。</p><p><strong>Q：我发给朋友的邀请码，朋友说无法使用，是什么原因？</strong></p><p>A：邀请码无法使用的常见原因：（1）朋友已经是平台注册用户，无法作为被邀请人；（2）邀请码输入有误，注意区分大小写及易混淆字符；（3）活动已结束，邀请链接过期。请让朋友检查账户状态，确认是全新注册，并重新通过邀请链接进入。</p><p><strong>Q：被邀请人开户后，邀请关系还能改吗？</strong></p><p>A：开户完成后，开户邀请关系即锁定，<strong>无法更改</strong>。入金邀请关系在首次入金完成后也同样锁定。如确实存在绑定错误（如注册时误填了别人的邀请码），请联系客服说明情况，客服会评估是否可以人工处理，但不保证一定可以更改。</p><p><strong>Q：我邀请了一个朋友，但他后来注销了账户，我的邀请关系还在吗？奖励会受影响吗？</strong></p><p>A：邀请关系记录在系统中，账户注销不会自动删除已绑定的邀请关系。但注销账户通常意味着相关任务进度也会受影响，已发放的奖励根据活动规则可能会被回收或取消。具体情况请联系客服核查。</p><p><strong>Q：同一个用户为什么会有三种不同的邀请关系？</strong></p><p>A：三种邀请关系分别对应用户生命周期的不同阶段——注册、开户（KYC）、首次入金。不同阶段的活动奖励可能归因到不同的邀请人，因此分开记录。对于大多数通过邀请链接注册的用户，三种关系通常绑定的是同一位邀请人。</p><p><strong>Q：邀请人信息（昵称、电话）显示不全，是正常的吗？</strong></p><p>A：是正常的。出于隐私保护，系统展示邀请人信息时会对手机号进行脱敏处理（如显示 138****5678）。如需确认邀请人身份，可联系对方核对。</p><p><strong>Q：活动要求「通过邀请注册」，但系统显示我没有邀请关系，怎么办？</strong></p><p>A：请先确认注册时是否通过邀请链接打开 APP 或填写了邀请码。如确认已操作但系统未记录，请联系客服，提供邀请人的邀请码及您的注册时间，客服会协助核查注册时的绑定情况。</p><p><strong>Q：被邀请人用了我的邀请码，但奖励算到了别人头上，怎么回事？</strong></p><p>A：可能原因：（1）被邀请人此前已通过其他渠道绑定了另一位邀请人的邀请关系；（2）被邀请人在注册时通过其他链接进入，实际绑定的是另一个邀请码；（3）不同任务的奖励归属不同类型的邀请人——例如注册和开户奖励可能分别归属不同邀请人（见「奖励归因」章节）。邀请关系以系统记录为准，如有争议请联系客服核查。</p><h2 id="绑定规则与违规判定" tabindex="-1">绑定规则与违规判定 <a class="header-anchor" href="#绑定规则与违规判定" aria-label="Permalink to &quot;绑定规则与违规判定&quot;">​</a></h2><ul><li>邀请码绑定以系统记录为准，口头约定或截图均不作为依据</li><li>管理员可人工修改开户或入金邀请关系（限被邀请人尚未完成对应步骤），普通用户如需修改需联系客服由后台处理</li><li>所有邀请关系均有变更记录，客服可查询历史变更情况</li></ul>',50)])])}const u=r(d,[["render",n]]);export{b as __pageData,u as default};
